// Determine source: single-product webhook, batch webhook (translate_missing), or scheduled
const webhookData = $('Translation Request Webhook').first()?.json;
const siteConfig = $('Site Config').first().json;
const defaultLanguages = (siteConfig.n8npress?.target_languages || [siteConfig.n8npress?.target_language || 'tr']).join(',');
const isSingleProduct = !!webhookData?.product_id;
const isBatchRequest = webhookData?.event === 'translate_missing' || !!webhookData?.fetch_pending;

if (isSingleProduct) {
  const body = webhookData.body || webhookData;
  return [{
    json: {
      product_ids: [body.product_id],
      target_languages: (body.target_languages || defaultLanguages).split(',').map(l => l.trim()),
      source: 'webhook'
    }
  }];
}

if (isBatchRequest) {
  const body = webhookData.body || webhookData;
  const langs = body.target_languages
    ? body.target_languages.split(',').map(l => l.trim())
    : defaultLanguages.split(',').map(l => l.trim());
  return [{
    json: {
      product_ids: [],
      target_languages: langs,
      source: 'batch_webhook',
      fetch_pending: true
    }
  }];
}

// Scheduled: use site-config target_languages
return [{
  json: {
    product_ids: [],
    target_languages: defaultLanguages.split(',').map(l => l.trim()),
    source: 'schedule',
    fetch_pending: true
  }
}];

const sourceData = $('Determine Source').first().json;
let productIds = sourceData.product_ids;

if (sourceData.fetch_pending) {
  const pending = $input.first().json;
  productIds = (pending.products || []).map(p => p.id).slice(0, 10);
}

const targetLanguages = sourceData.target_languages;

// Create one item per product-language combination
const items = [];
for (const productId of productIds) {
  for (const lang of targetLanguages) {
    items.push({
      json: { product_id: productId, target_language: lang }
    });
  }
}

if (items.length === 0) {
  return [{ json: { skip: true, message: 'No products to translate' } }];
}

return items;

