const response = $input.first().json;
const content = response.content?.[0]?.text || '{}';
let translated;
try {
  translated = JSON.parse(content);
} catch(e) {
  const match = content.match(/\{[\s\S]*\}/);
  translated = match ? JSON.parse(match[0]) : null;
}

if (!translated) {
  return [{ json: { valid: false, error: 'JSON parse failed', product_id: $json.product_id, target_language: $json.target_language } }];
}

const errors = [];

// Validate meta title length
if (translated.meta_title && translated.meta_title.length > 60) {
  errors.push(`Meta title too long: ${translated.meta_title.length} chars (max 60)`);
}

// Validate meta description length
if (translated.meta_description && translated.meta_description.length > 160) {
  errors.push(`Meta description too long: ${translated.meta_description.length} chars (max 160)`);
}

// Check brand name preservation (basic check)
const originalTitle = $('Fetch Product Data').first().json.title?.rendered || '';
const brandPatterns = originalTitle.match(/[A-Z][a-z]+(?:\s[A-Z][a-z]+)*/g) || [];
for (const brand of brandPatterns) {
  if (brand.length > 3 && !translated.title.includes(brand)) {
    errors.push(`Brand name possibly not preserved: ${brand}`);
  }
}

const productData = $('Fetch Product Data').first().json;

return [{
  json: {
    product_id: productData.id,
    product_name: productData.title?.rendered || productData.name,
    target_language: $('Build Translation Matrix').first().json.target_language,
    translated,
    valid: errors.length === 0,
    errors
  }
}];

// After saving translation, delete hreflang transient so tags regenerate
const saved = $input.first().json;
const productId = saved.product_id || saved.body?.product_id;
// The transient is auto-deleted on next page load if stale,
// but we log it for awareness.
return [{ json: { ...saved, hreflang_note: 'Hreflang tags will regenerate on next page view for product ' + productId } }];

const allItems = $input.all();
const now = new Date().toLocaleDateString('tr-TR', { timeZone: 'Europe/Istanbul' });
const siteName = $('Site Config').first().json.site?.name || 'Site';

const completed = allItems.filter(i => i.json.valid === true);
const needsReview = allItems.filter(i => i.json.valid === false);

let report = `Translation Pipeline Report - ${siteName}\nDate: ${now}\n\n`;
report += `Successful: ${completed.length} | Needs Review: ${needsReview.length}\n\n`;

if (needsReview.length > 0) {
  report += `Translations Needing Review:\n`;
  needsReview.forEach(item => {
    report += `  - ${item.json.product_name} (${item.json.target_language})\n`;
    (item.json.errors || []).forEach(e => {
      report += `    Error: ${e}\n`;
    });
  });
}

return [{ json: { report, date: now } }];
